import{_ as t,o as e,c as i,a3 as l}from"./chunks/framework.BTFg6ESq.js";const u=JSON.parse('{"title":"AI 信息解析","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/media-info-reader.md","filePath":"user-guide/tools/media-info-reader.md","lastUpdated":1778221347000}'),r={name:"user-guide/tools/media-info-reader.md"};function o(s,a,n,h,d,p){return e(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="ai-信息解析" tabindex="-1">AI 信息解析 <a class="header-anchor" href="#ai-信息解析" aria-label="Permalink to &quot;AI 信息解析&quot;">​</a></h1><blockquote><p>从图片中提取 AI 生成参数、工作流、角色卡等元数据，一键还原创作配方。</p></blockquote><h2 id="功能概览" tabindex="-1">功能概览 <a class="header-anchor" href="#功能概览" aria-label="Permalink to &quot;功能概览&quot;">​</a></h2><ul><li><strong>Stable Diffusion WebUI 参数提取</strong> — 自动读取图片中的正反提示词（Positive/Negative Prompt）、采样参数、模型信息、Civitai 资源引用等。</li><li><strong>ComfyUI 工作流还原</strong> — 解析图片中嵌入的 ComfyUI 工作流 JSON，可直接复制用于复现或调试。</li><li><strong>SillyTavern 角色卡片可视化</strong> — 识别并结构化展示 ST 角色卡（chara_card_v2/v3），包括角色设定、提示词策略、对话示例等。</li><li><strong>AIO Bundle 解析</strong> — 解析 AIO Agent Bundle 包（支持 ZIP 压缩包），展示 Agent 身份、思维导向、预设消息流、运行参数和关联资产。</li><li><strong>完整元数据查勘</strong> — 展示图片的原始 EXIF 全量 JSON，供高级用户深度排查。</li><li><strong>一键发送到聊天</strong> — 将解析结果按当前标签页的内容发送到 LLM 聊天工具，方便继续追问或参考。</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><ol><li>在主页点击 <strong>AI 信息解析</strong> 卡片进入工具。</li><li>将一张 AI 生成的图片（PNG / JPG / WebP）<strong>拖放</strong>到左侧预览区，或点击「选择图片」按钮打开文件选择器，也可以直接 <strong>Ctrl+V</strong> 粘贴剪贴板中的图片。</li><li>右侧面板会自动解析并显示匹配的标签页，按优先级排序： <ul><li><strong>AIO 可视化</strong>（若图片包含 AIO Bundle）</li><li><strong>WebUI Info</strong>（若图片包含 WebUI 参数）</li><li><strong>ComfyUI Workflow</strong>（若图片包含工作流）</li><li><strong>ST 可视化</strong>（若图片包含角色卡）</li><li><strong>完整元数据</strong>（兜底，展示原始 EXIF）</li></ul></li><li>点击「发送到聊天」可将当前标签页的内容推送至 LLM 聊天界面。</li></ol><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="图片导入" tabindex="-1">图片导入 <a class="header-anchor" href="#图片导入" aria-label="Permalink to &quot;图片导入&quot;">​</a></h3><p>左侧预览面板提供三种导入方式：</p><table tabindex="0"><thead><tr><th>方式</th><th>操作</th></tr></thead><tbody><tr><td><strong>拖放</strong></td><td>从文件管理器直接拖拽图片文件到预览区域</td></tr><tr><td><strong>选择文件</strong></td><td>点击「选择图片」按钮，从系统文件对话框选取</td></tr><tr><td><strong>粘贴</strong></td><td>复制图片后按下 Ctrl+V，直接从剪贴板导入</td></tr></tbody></table><p>图片加载后，解析器会立即启动，预览区右上角会显示「正在解析...」状态。</p><h3 id="webui-信息" tabindex="-1">WebUI 信息 <a class="header-anchor" href="#webui-信息" aria-label="Permalink to &quot;WebUI 信息&quot;">​</a></h3><p>当图片由 Stable Diffusion WebUI / AUTOMATIC1111 / Forge 等生成时，此标签页展示：</p><ul><li><strong>Positive Prompt</strong> — 正面提示词全文。</li><li><strong>Negative Prompt</strong> — 负面提示词全文。</li><li><strong>Generation Info</strong> — 生成参数键值对，包括 Steps、Sampler、CFG scale、Seed、Size、Model、VAE 等。</li><li><strong>Civitai Resources</strong> — 图片引用的 Civitai 模型资源列表，按类型（Checkpoint / LoRA / LyCORIS / Embedding）使用不同颜色标签，并显示权重。</li></ul><p>每个区块均配有复制按钮，方便将提示词或参数单独复制使用。</p><h3 id="comfyui-workflow" tabindex="-1">ComfyUI Workflow <a class="header-anchor" href="#comfyui-workflow" aria-label="Permalink to &quot;ComfyUI Workflow&quot;">​</a></h3><p>展示从图片中提取的 ComfyUI 工作流 JSON，以只读代码编辑器呈现，支持语法高亮和折叠。可一键复制完整工作流，用于在 ComfyUI 中导入复现。</p><h3 id="sillytavern-角色卡" tabindex="-1">SillyTavern 角色卡 <a class="header-anchor" href="#sillytavern-角色卡" aria-label="Permalink to &quot;SillyTavern 角色卡&quot;">​</a></h3><p>支持 chara_card_v2 和 chara_card_v3 格式，以可视化的卡片布局展示角色信息：</p><ul><li><strong>角色概要</strong> — 名称、版本号、作者、标签云。</li><li><strong>角色设定</strong> — 角色描述（Description）、性格特质（Personality）。</li><li><strong>提示词策略</strong> — System Prompt、Post History Instructions。</li><li><strong>对话与场景</strong> — 场景设定（Scenario）、首条消息（First Message）、备用问候语（Alternate Greetings）、对话示例（Message Examples）。</li><li><strong>作者备注</strong> — Creator Notes。</li></ul><p>同时提供 <strong>ST 源码</strong> 标签页，展示原始 JSON，供需要手动编辑或二次处理的用户使用。</p><h3 id="aio-bundle-可视化" tabindex="-1">AIO Bundle 可视化 <a class="header-anchor" href="#aio-bundle-可视化" aria-label="Permalink to &quot;AIO Bundle 可视化&quot;">​</a></h3><p>当图片中嵌入了 AIO Agent Bundle 时，以精美的信息卡片展示每个 Agent：</p><ul><li><strong>身份信息</strong> — 头像、显示名称、版本、描述、模型 ID、资产数量。</li><li><strong>思维导向</strong> — LLM 思维规则（think rules）和 Persona / System Prompt。</li><li><strong>预设消息流</strong> — 以时间线形式展示预设消息（system / user / assistant），含角色标签、注入策略（深度注入 / 位置注入）和模型匹配条件。</li><li><strong>运行参数</strong> — 采样控制（Temperature / Top P / Reasoning Effort）和上下文压缩配置。</li><li><strong>关联资产</strong> — 按分组展示资产 ID 和大小。</li></ul><p>支持 JSON 和 YAML 两种格式。同时提供 <strong>AIO 源码</strong> 标签页，可查看或复制原始 Manifest。</p><h3 id="完整元数据" tabindex="-1">完整元数据 <a class="header-anchor" href="#完整元数据" aria-label="Permalink to &quot;完整元数据&quot;">​</a></h3><p>以代码编辑器形式展示图片的完整 EXIF JSON，包含所有可读取的元数据字段。适合高级用户进行深度排查或数据分析。</p><h3 id="发送到聊天" tabindex="-1">发送到聊天 <a class="header-anchor" href="#发送到聊天" aria-label="Permalink to &quot;发送到聊天&quot;">​</a></h3><p>点击预览区右上角的「发送到聊天」按钮，系统会：</p><ol><li>将当前显示的标签页内容（提示词、工作流、角色卡或元数据）格式化后发送到 LLM 聊天工具。</li><li>若图片已作为资产导入，附件也会一并发送。</li></ol><p>例如，在 WebUI Info 标签页点击发送，聊天输入框会自动填入：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">来自图片的 Stable Diffusion WebUI 信息：</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\`\\`\\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">text</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Positive Prompt: ...</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Negative Prompt: ...</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Steps: 30, Sampler: DPM++ 2M Karras, CFG scale: 7, ...</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\`\\`\\`</span></span></code></pre></div><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="在聊天中复用解析结果" tabindex="-1">在聊天中复用解析结果 <a class="header-anchor" href="#在聊天中复用解析结果" aria-label="Permalink to &quot;在聊天中复用解析结果&quot;">​</a></h3><p>解析出提示词或角色卡后，可一键发送到 LLM 聊天工具，让 AI 助手帮你：</p><ul><li>优化或改写提示词</li><li>分析角色卡的设定</li><li>诊断 ComfyUI 工作流问题</li><li>提取角色卡中的关键设定用于创作</li></ul><h3 id="多端协同" tabindex="-1">多端协同 <a class="header-anchor" href="#多端协同" aria-label="Permalink to &quot;多端协同&quot;">​</a></h3><p>桌面端解析的图片可通过资产管理器统一管理，方便反复查阅或跨工具调用。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="为什么有的图片解析不出内容" tabindex="-1">为什么有的图片解析不出内容？ <a class="header-anchor" href="#为什么有的图片解析不出内容" aria-label="Permalink to &quot;为什么有的图片解析不出内容？&quot;">​</a></h3><p>并非所有图片都包含元数据。以下情况可能导致解析为空：</p><ul><li>图片是通过截图或屏幕录制生成的（不包含 AI 生成参数）。</li><li>图片经过了有损压缩或二次保存，导致元数据被剥离。</li><li>图片是由不同的 AI 工具生成的，而该工具的元数据格式未被本项目支持。</li></ul><p>此时右侧面板会显示「未检测到 AI 生成信息」，建议检查图片来源。</p><h3 id="支持哪些图片格式" tabindex="-1">支持哪些图片格式？ <a class="header-anchor" href="#支持哪些图片格式" aria-label="Permalink to &quot;支持哪些图片格式？&quot;">​</a></h3><p>支持 PNG、JPG、JPEG、WebP 四种常见格式。PNG 格式对元数据的兼容性最好，建议将重要的 AI 生成图片保存为 PNG。</p><h3 id="解析的结果安全吗" tabindex="-1">解析的结果安全吗？ <a class="header-anchor" href="#解析的结果安全吗" aria-label="Permalink to &quot;解析的结果安全吗？&quot;">​</a></h3><p>所有解析完全在本地完成，无需联网。图片文件和元数据均不会上传至任何服务器。</p><h3 id="我能在手机或平板上使用吗" tabindex="-1">我能在手机或平板上使用吗？ <a class="header-anchor" href="#我能在手机或平板上使用吗" aria-label="Permalink to &quot;我能在手机或平板上使用吗？&quot;">​</a></h3><p>移动端暂未提供此工具，请在桌面端使用。</p><h3 id="解析后的数据能否导出" tabindex="-1">解析后的数据能否导出？ <a class="header-anchor" href="#解析后的数据能否导出" aria-label="Permalink to &quot;解析后的数据能否导出？&quot;">​</a></h3><p>当前标签页的每个信息区块都配有复制按钮。你也可以通过「发送到聊天」将结构化的内容导出到 LLM 聊天界面，再自行复制保存。</p>',51)])])}const c=t(r,[["render",o]]);export{u as __pageData,c as default};
